class CsvReport {
  generate(data: Row[]): string {
    const validated = this.validate(data);
    const transformed = this.transform(validated);
    const output = this.renderCsv(transformed);
    this.audit(output.length);
    return output;
  }
}
class JsonReport {
  generate(data: Row[]): string {
    const validated = this.validate(data);
    const transformed = this.transform(validated);
    const output = this.renderJson(transformed);
    this.audit(output.length);
    return output;
  }
}

class PdfJob {
  run(data: Row[]): void { this.load(data); this.clean(); this.renderPdf(); this.notify(); }
}
class CsvJob {
  run(data: Row[]): void { this.load(data); this.clean(); this.renderCsv(); this.notify(); }
}
class XmlJob {
  run(data: Row[]): void { this.load(data); this.clean(); this.renderXml(); this.notify(); }
